python3 -c "
import json, sys, os, re
d = json.load(sys.stdin)
ti = d.get('tool_input', {})
p = ti.get('file_path', '')
if not p or not p.endswith('.dart'):
    sys.exit(0)
skip = ['test/', '_test.dart', '.g.dart', '.freezed.dart']
if any(s in p for s in skip):
    sys.exit(0)
content = ti.get('content', '') or ti.get('new_string', '')
if not content:
    sys.exit(0)
imports = re.findall(r"import\s+['\"](.+?)['\"];", content)
if not imports:
    sys.exit(0)
def has_layer(imp, keywords):
    return any(k in imp.lower() for k in keywords)
bn = os.path.basename(p).lower()
violations = []
if '_screen.' in bn or '/screens/' in p.lower():
    for imp in imports:
        if has_layer(imp, ['repository', '/repositories/', 'model', '/models/']):
            if not has_layer(imp, ['provider', 'view_model', 'cubit', 'bloc']):
                violations.append(f'Screen imports {imp} (should go through Provider/Cubit layer)')
elif '_provider.' in bn or '/providers/' in p.lower():
    for imp in imports:
        if has_layer(imp, ['screen', '/screens/']):
            violations.append(f'Provider imports {imp} (screens depend on providers, not vice versa)')
if violations:
    msg = '; '.join(violations[:2])
    print(json.dumps({'systemMessage': f'[BOUNDARY] {msg}. See coding-conventions.md Layer Boundaries.'}))
sys.exit(0)
"
